// CAS retry loop — what AtomicInteger.incrementAndGet does internally
public int myIncrement(AtomicInteger ai) {
    while (true) {
        int current = ai.get();
        int next    = current + 1;
        if (ai.compareAndSet(current, next)) // CAS
            return next;                     // success
        // else: another thread changed value, retry
    }
}

